// Minimal jsPDF stub for local testing — provides just enough API surface
// for exportProjectPDF / exportEstimatePDF / exportShopPDF to run without
// errors. Does not produce real PDFs.
(function(root) {
  function jsPDF() {
    this._pages = 1;
    this._y = 10;
    this._fontSize = 12;
    this._textColor = '0,0,0';
    this._drawColor = '0,0,0';
    this._fillColor = '255,255,255';
    this._font = 'helvetica';
    this._fontStyle = 'normal';
  }
  var self;
  Object.defineProperty(jsPDF.prototype, 'internal', { get: function() {
    var inst = this;
    return {
      pageSize: { getWidth: function(){ return 210; }, getHeight: function(){ return 297; } },
      getNumberOfPages: function(){ return inst._pages; }
    };
  }});
  jsPDF.prototype.setFontSize = function(s){ this._fontSize = s; return this; };
  jsPDF.prototype.setFont = function(f, s){ this._font = f; this._fontStyle = s||'normal'; return this; };
  jsPDF.prototype.setTextColor = function(r,g,b){ this._textColor = [r,g,b].join(','); return this; };
  jsPDF.prototype.setDrawColor = function(r,g,b){ this._drawColor = [r,g,b].join(','); return this; };
  jsPDF.prototype.setFillColor = function(r,g,b){ this._fillColor = [r,g,b].join(','); return this; };
  jsPDF.prototype.text = function(){ return this; };
  jsPDF.prototype.line = function(){ return this; };
  jsPDF.prototype.rect = function(){ return this; };
  jsPDF.prototype.addPage = function(){ this._pages++; return this; };
  jsPDF.prototype.setPage = function(){ return this; };
  jsPDF.prototype.getNumberOfPages = function(){ return this._pages; };
  jsPDF.prototype.splitTextToSize = function(text, maxWidth){
    if (!text) return [''];
    return [String(text)];
  };
  jsPDF.prototype.getTextWidth = function(text){ return (text||'').length * 2; };
  jsPDF.prototype.save = function(filename){
    root.__jspdf_last_save = filename;
    var blob = new Blob(['%PDF-1.4 stub'], {type:'application/pdf'});
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = filename || 'document.pdf';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };
  root.jspdf = { jsPDF: jsPDF };
})(typeof window !== 'undefined' ? window : this);
